<?php//**************************************************// * Login page.  There are links to this page from *// * the header on every other page for logged-out  *// * users only.                                    *// **************************************************/require_once('../assets/db_inc_login_funcs.php');// If they're logged in, log them out// They shouldn't be able to see this page logged-in// This allows the same page to be used as a logout scriptif ($LOGGED_IN = user_isloggedin()) {  user_logout();  $_COOKIE['user_name'] = '';  unset($LOGGED_IN);}if ($_POST['submit'] == 'nu inloggen') {  if (strlen($_POST['user_name']) <= 25 && strlen($_POST['password']) <=25) {    $feedback = user_login();  } else {    $feedback = '<img src="../pics/macmandwn.gif" width="23" height="28" />  ERROR - De accountnaam of het paswoord zijn zp niet geldig... :-(';  }  if ($feedback == 1) {    // On successful login, redirect to homepage    session_name("HelpDiskAlc");	session_start();    header("Location: index.php");  } else {    $feedback_str = "<img src=\"../pics/macmandwn.gif\" width=\"23\" height=\"28\" /> <P class=\"errormess\">$feedback</P>";  }} else {  $feedback_str = '';}// ----------------// DISPLAY THE FORM// ----------------include_once('db_header_footer.php');site_header('Login');// Superglobals don't work with heredoc$php_self = $_SERVER['PHP_SELF'];$login_form = <<< EOLOGINFORM<TABLE CELLPADDING=0 CELLSPACING=0 BORDER=0 ALIGN=CENTER WIDTH=621><TR>  <TD ROWSPAN=2><IMG WIDTH=15 HEIGHT=1 SRC=../images/spacer.gif></TD>  <TD WIDTH=606 HEIGHT=1><IMG WIDTH=606 HEIGHT=1 SRC=../images/spacer.gif></TD></TR><TR> <TD>$feedback_str<P><strong>Inloggen</strong></P><FORM ACTION="$php_self" METHOD="POST"><P>Account naam<BR><INPUT TYPE="TEXT" NAME="user_name" VALUE="" SIZE="10" MAXLENGTH="15"></P><P>Password<BR><INPUT TYPE="password" NAME="password" VALUE="" SIZE="10" MAXLENGTH="15"></P><P><INPUT TYPE="SUBMIT" NAME="submit" VALUE="nu inloggen"></P></FORM>$http_get('url'); if isset('$url'){header ("location :"$url);}  </TD></TR></TABLE>EOLOGINFORM;echo $login_form;site_footer();?>